function xml(s) {
  return String(s ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;')
    .replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

// ──────────────────────────────────────────────────────────────
// Localized legend strings (auto-derived per spec).
// Extended by adding a new `lang` key; missing keys fall back to 'ko'.
