    editable_cell:  '노랑 셀',
    editable_label: '편집 가능',
  },
  en: {
    required:       'Required',
    dropdown:       '▼ Multi-select',
    range:          '~ Range (LOW~HIGH)',
    status_done:    'Done',
    status_partial: 'Partial',
    status_open:    'Open',
    hotspot_text:   'Blue underline',
    hotspot_label:  '= Hotspot (click to navigate)',
    editable_cell:  'Yellow cell',
    editable_label: '= Editable',
