function findBrowser() {
  const localAppData = process.env.LOCALAPPDATA || '';
  const candidates = platform() === 'win32'
    ? [
      // Edge (modern x64 install path) — Win11 default location since 2022.
      'C:\\Program Files\\Microsoft\\Edge\\Application\\msedge.exe',
      // Edge (legacy WOW6432 install path) — older Win10 / downgraded installs.
      'C:\\Program Files (x86)\\Microsoft\\Edge\\Application\\msedge.exe',
      // Edge — non-admin user install (becoming common on locked-down corp machines).
      localAppData && `${localAppData}\\Microsoft\\Edge\\Application\\msedge.exe`,
      // Chrome (both bitness variants).
      'C:\\Program Files\\Google\\Chrome\\Application\\chrome.exe',
      'C:\\Program Files (x86)\\Google\\Chrome\\Application\\chrome.exe',
      // Chrome — non-admin user install.
      localAppData && `${localAppData}\\Google\\Chrome\\Application\\chrome.exe`,
    ].filter(Boolean)
    : platform() === 'darwin'
      ? [
        '/Applications/Google Chrome.app/Contents/MacOS/Google Chrome',
        '/Applications/Microsoft Edge.app/Contents/MacOS/Microsoft Edge',
      ]
      : [
        // Linux — try common absolute paths first (PATH may be empty in CI/sandbox),
        // then fall back to PATH lookup via `which`.
        '/usr/bin/google-chrome-stable',
        '/usr/bin/google-chrome',
        '/usr/bin/chromium',
        '/usr/bin/chromium-browser',
        '/usr/bin/microsoft-edge',
        '/snap/bin/chromium',
        'google-chrome', 'chromium', 'chromium-browser', 'microsoft-edge',
      ];

